[
  {
    "text": "GeoFuse-MV3D improves over the MV-SAM3D baseline by reducing Chamfer Distance (CD) by 2.20% and LPIPS by 2.02% while increasing PSNR by 2.36% and SSIM by 1.03%.",
    "topic": "Geometry-Aware Reconstruction"
  },
  {
    "text": "The upgraded KnowledgeBank improves over ReasoningBank by 4.53% on Terminal-Bench SR and 3.73% on SWE-Bench resolve rate, while reducing adverse side effects (AS) by 4.95% and 5.65%, respectively.",
    "topic": "Governed Long-Term Memory"
  },
  {
    "text": "GeoFuse-MV3D is a geometry-prior-guided MV-SAM3D reconstruction branch that verifies external geometry cues with input-view masks, applies soft visual-hull support, performs axis-wise refinement, and fuses only geometry while preserving appearance.",
    "topic": "Geometry-Aware Reconstruction"
  },
  {
    "text": "KnowledgeBank is upgraded into a governed long-term memory system with explicit quality, confidence, lifecycle, verifier, and conflict metadata, together with precision-oriented retrieval.",
    "topic": "Governed Long-Term Memory"
  },
  {
    "text": "GeneralVLA-2 provides a hierarchical interface for converting language and RGB-D observations into 3D end-effector paths for robot planning.",
    "topic": "Robot Planning Interface"
  }
]
